function pc_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function pc_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function pc_c($v){return strtoupper(trim((string)$v));}
function pc_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
